import json


def lambda_handler(event, context):
    """
    AWS Lambda function that serves user data as JSON for a single-page application.
    Configured with permissive CORS headers for development flexibility.
    """
    
    # Define CORS headers to allow requests from any origin
    cors_headers = {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Headers": "Content-Type,X-Amz-Date,Authorization,X-Api-Key,X-Amz-Security-Token,X-Requested-With",
        "Access-Control-Allow-Methods": "GET,POST,PUT,DELETE,OPTIONS",
        "Access-Control-Max-Age": "86400",
        "Content-Type": "application/json"
    }
    
    # Handle preflight OPTIONS request
    http_method = event.get("httpMethod", "") or event.get("requestContext", {}).get("http", {}).get("method", "")
    
    if http_method == "OPTIONS":
        return {
            "statusCode": 200,
            "headers": cors_headers,
            "body": json.dumps({"message": "CORS preflight response"})
        }
    
    # Extract path and query parameters
    path = event.get("path", "/") or event.get("rawPath", "/")
    path_parameters = event.get("pathParameters") or {}
    query_parameters = event.get("queryStringParameters") or {}
    
    try:
        # Route handling
        if path == "/users" or path == "/api/users":
            response_body = _get_users(query_parameters)
            status_code = 200
        elif path.startswith("/users/") or path.startswith("/api/users/"):
            user_id = path_parameters.get("userId") or path.split("/")[-1]
            response_body = _get_user_by_id(user_id)
            if response_body is None:
                status_code = 404
                response_body = {"error": "User not found", "userId": user_id}
            else:
                status_code = 200
        elif path == "/health" or path == "/api/health":
            response_body = {"status": "healthy", "service": "user-data-api"}
            status_code = 200
        else:
            response_body = {"error": "Not found", "path": path}
            status_code = 404
            
    except Exception as e:
        response_body = {"error": "Internal server error", "message": str(e)}
        status_code = 500
    
    return {
        "statusCode": status_code,
        "headers": cors_headers,
        "body": json.dumps(response_body, default=str)
    }


